const STABLE_READINGS = 3;
const FRESH_MS = 15000;
const ZERO_OFF_MS = 300000;
const MIN_CHANGE_MS = 8000;
const OUTSIDE_WINDOW_OFF_MS = 300000;
const AUTOMATION_COUNT_SOURCE = 'total-count';
const CONTROLLED = [2,3,4,6,7,8];
const TOPICS = {2:'lab/control/relay2/set',3:'lab/control/relay3/set',4:'lab/control/relay4/set',6:'lab/control/relay6/set',7:'lab/control/relay7/set',8:'lab/control/relay8/set'};
function m(topic,payload,retain=false){return {topic,payload:typeof payload==='string'?payload:JSON.stringify(payload),retain};}
function send(commands,diagnostics){node.send([commands.length?commands:null,diagnostics.length?diagnostics:null]);}
function nowMinutes(ts){const d=new Date(ts);return d.getHours()*60+d.getMinutes();}
function withinFallbackWindow(ts){const mns=nowMinutes(ts);const morning=(8*60+30)<=mns&&mns<(12*60+30);const afternoon=(13*60)<=mns&&mns<(16*60+30);return morning||afternoon;}
function desired(stage){const s={2:'OFF',3:'OFF',4:'OFF',6:'OFF',7:'OFF',8:'OFF'};if(stage==='ONE'){s[2]='ON';s[7]='ON';}else if(stage==='TWO_THREE'){s[2]='ON';s[3]='ON';s[6]='ON';s[7]='ON';}else if(stage==='FOUR_PLUS'){for(const relay of Object.keys(s))s[relay]='ON';}return s;}
function stageFor(count){return count<=0?'EMPTY':count===1?'ONE':count<4?'TWO_THREE':'FOUR_PLUS';}
function healthy(now){const lastHeartbeat=context.get('lastHeartbeat')||0;const lastCount=context.get('lastCountTs')||0;return context.get('serviceOnline')===true&&context.get('sourceHealthy')===true&&lastHeartbeat>0&&lastCount>0&&(now-lastHeartbeat)<=FRESH_MS&&(now-lastCount)<=FRESH_MS;}
function actual(){return context.get('actual')||{};}
function lastCommand(){return context.get('lastCommand')||{};}
function manualOverrides(){return context.get('manualOverrides')||{};}
function hasManualOverrides(){return Object.keys(manualOverrides()).length > 0;}
function setManualOverride(relay,state){const overrides=manualOverrides();overrides[String(relay)]=state;context.set('manualOverrides',overrides);}
function clearManualOverride(payload){if(payload===undefined||payload===null||String(payload).toLowerCase()==='all'){context.set('manualOverrides',{});return 'cleared all manual overrides';}const overrides=manualOverrides();if(Array.isArray(payload)){for(const relay of payload)delete overrides[String(relay)];}else{delete overrides[String(payload)];}context.set('manualOverrides',overrides);return 'cleared requested manual override(s)';}
function applyOverrides(wanted){const merged=Object.assign({},wanted);for(const [relay,state] of Object.entries(manualOverrides())){merged[relay]=state;}return merged;}
function commandsFor(wanted){const a=actual(),last=lastCommand(),commands=[];for(const [relay,state] of Object.entries(wanted)){if(a[relay]!==state&&last[relay]!==state){commands.push(m(TOPICS[relay],state,false));last[relay]=state;}}context.set('lastCommand',last);return commands;}
function publishState(diags){diags.push(m('lab/automation/status','online',true));diags.push(m('lab/automation/mode_state',context.get('mode')||'manual',true));diags.push(m('lab/automation/count_source',AUTOMATION_COUNT_SOURCE,true));diags.push(m('lab/automation/manual_override_state',manualOverrides(),true));diags.push(m('lab/automation/vision_health',healthy(now)?'healthy':'stale',true));const lastCount=context.get('lastCountTs')||0;diags.push(m('lab/automation/vision_age_seconds',lastCount?Math.floor((now-lastCount)/1000):-1,true));}
function fallbackTarget(now){const lastKnown=context.get('lastKnownAutomation')||desired('FOUR_PLUS');if(withinFallbackWindow(now)){context.set('fallbackOffSince',0);return {decisionSource:'TIMETABLE_FALLBACK',stage:'TIMETABLE_FALLBACK',wanted:applyOverrides(lastKnown),reason:'vision unhealthy -> timetable fallback'};}let offSince=context.get('fallbackOffSince')||0;if(!offSince){offSince=now;context.set('fallbackOffSince',offSince);}if((now-offSince)<OUTSIDE_WINDOW_OFF_MS){return {decisionSource:'TIMETABLE_HOLD',stage:'TIMETABLE_HOLD',wanted:applyOverrides(lastKnown),reason:'vision unhealthy -> preserving last known state outside timetable'};}return {decisionSource:'VISION_STALE',stage:'TIMETABLE_OFF',wanted:applyOverrides(desired('EMPTY')),reason:'vision unhealthy -> safe delayed off outside timetable'};}
function rememberAutomation(stage,wanted,now){context.set('activeStage',stage);context.set('lastApply',now);context.set('pendingStage','');context.set('pendingReads',0);context.set('lastKnownAutomation',Object.assign({},wanted));}
function automationTarget(count,now){const stage=stageFor(count);if(count===0){let zeroSince=context.get('zeroSince')||0;if(!zeroSince){zeroSince=now;context.set('zeroSince',zeroSince);}if((now-zeroSince)<ZERO_OFF_MS){return {decisionSource:'PEOPLE_COUNT',stage:'ZERO_HOLD',wanted:applyOverrides(context.get('lastKnownAutomation')||desired(context.get('activeStage')||'EMPTY')),reason:'healthy zero hold'};}}else{context.set('zeroSince',0);}if(stage===context.get('activeStage')){return {decisionSource:'PEOPLE_COUNT',stage,wanted:applyOverrides(context.get('lastKnownAutomation')||desired(stage)),reason:'stage unchanged'};}let pending=context.get('pendingStage')||'';let reads=context.get('pendingReads')||0;if(stage===pending)reads++;else{pending=stage;reads=1;}context.set('pendingStage',pending);context.set('pendingReads',reads);if(reads<STABLE_READINGS||now-(context.get('lastApply')||0)<MIN_CHANGE_MS){return {decisionSource:'PEOPLE_COUNT',stage:'STABILIZING',wanted:applyOverrides(context.get('lastKnownAutomation')||desired(context.get('activeStage')||'EMPTY')),reason:`stabilizing ${stage}`};}const base=desired(stage);rememberAutomation(stage,base,now);return {decisionSource:'PEOPLE_COUNT',stage,wanted:applyOverrides(base),reason:`applied ${stage}`};}
const topic=String(msg.topic||'');
const now=Date.now();
const mode=context.get('mode')||'manual';
let diagnostics=[];
if(topic==='lab/automation/mode'){
  const next=String(msg.payload).trim().toLowerCase();
  const value=['manual','monitor','auto'].includes(next)?next:'manual';
  context.set('mode',value);
  if(value!=='auto'){context.set('zeroSince',0);context.set('fallbackOffSince',0);}
  diagnostics.push(m('lab/automation/status','online',true));
  diagnostics.push(m('lab/automation/mode_state',value,true));
  diagnostics.push(m('lab/automation/count_source',AUTOMATION_COUNT_SOURCE,true));
  diagnostics.push(m('lab/automation/last_action',`mode set to ${value}`,true));
  diagnostics.push(m('lab/automation/priority_state', value==='manual' ? (hasManualOverrides() ? 'MANUAL_OVERRIDE' : 'MANUAL') : value==='monitor' ? 'MONITOR' : 'VISION_STALE', true));
  send([],diagnostics);
  return null;
}
if(topic==='lab/automation/manual_override/clear'){
  diagnostics.push(m('lab/automation/last_action',clearManualOverride(msg.payload),true));
  diagnostics.push(m('lab/automation/manual_override_state',manualOverrides(),true));
  diagnostics.push(m('lab/automation/priority_state', (context.get('mode')||'manual')==='manual' ? 'MANUAL' : ((context.get('mode')||'manual')==='monitor' ? 'MONITOR' : (healthy(now) ? 'PEOPLE_COUNT' : 'VISION_STALE')), true));
  send([],diagnostics);
  return null;
}
if(topic==='lab/vision/status'){
  let value=String(msg.payload).toLowerCase();
  try{const parsed=typeof msg.payload==='object'?msg.payload:JSON.parse(String(msg.payload));value=String(parsed.status||value).toLowerCase();}catch(e){}
  context.set('serviceOnline',value==='online'||value==='healthy');
  return null;
}
if(topic==='lab/vision/source_status'){
  context.set('sourceHealthy',String(msg.payload).toLowerCase()==='healthy');
  return null;
}
if(topic==='lab/vision/heartbeat'){
  context.set('lastHeartbeat',now);
  return null;
}
if(topic==='lab/control/status'){
  context.set('relayOnline',String(msg.payload).toLowerCase()==='online');
  return null;
}
const stateMatch=topic.match(/^lab\/control\/relay(\d+)\/state$/);
if(stateMatch){
  const relay=stateMatch[1];
  const state=String(msg.payload).toUpperCase();
  const a=actual();
  a[relay]=state;
  context.set('actual',a);
  const last=lastCommand();
  if((context.get('mode')||'manual')==='manual' || (last[relay] && last[relay]!==state)){
    setManualOverride(relay,state);
  }
  return null;
}
if(topic==='lab/automation/internal/tick'){
  publishState(diagnostics);
  if((context.get('mode')||'manual')==='manual'){
    diagnostics.push(m('lab/automation/priority_state', hasManualOverrides() ? 'MANUAL_OVERRIDE' : 'MANUAL', true));
    send([],diagnostics);
    return null;
  }
  if((context.get('mode')||'manual')==='monitor'){
    diagnostics.push(m('lab/automation/priority_state', healthy(now) ? 'PEOPLE_COUNT' : 'VISION_STALE', true));
  }
  if(!healthy(now)){
    const fb=fallbackTarget(now);
    diagnostics.push(m('lab/automation/priority_state',fb.decisionSource,true));
    diagnostics.push(m('lab/automation/warning',fb.reason,false));
    if((context.get('mode')||'manual')==='auto'){
      const commands=commandsFor(fb.wanted);
      send(commands,diagnostics);
      return null;
    }
    send([],diagnostics);
    return null;
  }
  send([],diagnostics);
  return null;
}
if(topic!=='lab/vision/people_count') return null;
let payload=msg.payload;
if(Buffer.isBuffer(payload))payload=payload.toString();
if(typeof payload==='string'){try{payload=JSON.parse(payload);}catch(e){diagnostics.push(m('lab/automation/warning','invalid people_count payload ignored',false));send([],diagnostics);return null;}}
let ts=Number(payload&&payload.timestamp||0); if(ts<100000000000) ts*=1000;
const count=Number(payload&&payload.stable_count);
const valid=payload&&payload.source_healthy===true&&payload.status==='online'&&Number.isInteger(count)&&count>=0&&Math.abs(now-ts)<=FRESH_MS;
if(valid){context.set('latestCount',count);context.set('lastCountTs',now);context.set('serviceOnline',true);context.set('sourceHealthy',true);}publishState(diagnostics);
if(!valid){const fb=fallbackTarget(now);diagnostics.push(m('lab/automation/warning',fb.reason,false));diagnostics.push(m('lab/automation/priority_state',fb.decisionSource,true));const commands=((context.get('mode')||'manual')==='auto')?commandsFor(fb.wanted):[];send(commands,diagnostics);return null;}
diagnostics.push(m('lab/automation/accepted_count',{publisher:'nodered-lab-priority',count,target:stageFor(count),count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},false));
if((context.get('mode')||'manual')==='manual'){
  diagnostics.push(m('lab/automation/priority_state',hasManualOverrides() ? 'MANUAL_OVERRIDE' : 'MANUAL',true));
  send([],diagnostics);
  return null;
}
const target=healthy(now)?automationTarget(count,now):fallbackTarget(now);
diagnostics.push(m('lab/automation/priority_state',target.decisionSource,true));
diagnostics.push(m('lab/automation/intended_state',{publisher:'nodered-lab-priority',stage:target.stage,count,relays:target.wanted,reason:target.reason,decision_source:target.decisionSource,count_source:AUTOMATION_COUNT_SOURCE,timestamp:Math.floor(now/1000)},true));
if((context.get('mode')||'manual')==='monitor'){
  send([],diagnostics);
  return null;
}
const commands=(target.stage==='STABILIZING')?[]:commandsFor(target.wanted);
send(commands,diagnostics);
return null;
